import Navbar from "../components/Navbar";

function Login() {
  return (
    <div>
        <Navbar />
        <h2>Login</h2>
        <input placeholder="Correo" />
        <input placeholder="Password" type="password" />
        <button>Ingresar</button>
    </div>
  );
}

export default Login;
